"""
MKT Original Commentary — Ezekiel chapters 6–10
Run: python3 scripts/zc-original-ezekiel-6-10-fill.py

Source data used:
- data/interlinear/ezekiel.json
- data/translation/glossary-hebrew.json (gillulim, kavod, tav, etc.)
- Standard BDB lexicon knowledge for key terms

Key decisions in this range:
- gillulim rendered as 'idols' (contemptuous dung-derived term) throughout
- kavod traced from ch 1 through chs 8-10 as a structural thread
- tav (9:4) noted as the last letter of the Hebrew alphabet, marking completeness
- ch 10 cherubim explicitly identified as ch 1 chayyot — the text itself makes this connection
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

EZEKIEL_ORIGINAL = {
"6": {
    "1": '<p>Standard prophetic introduction marking a fresh oracle. The phrase <strong>wayehi devar-YHWH elai</strong> (\'the word of YHWH came to me\') is Ezekiel\'s most frequent commissioning formula, occurring over 50 times in the book. Each occurrence marks the beginning of a discrete divine communication event, not merely an internal impression.</p>',
    "2": '<p><strong>harim Yisrael</strong> (\'mountains of Israel\'): the mountains are addressed as if persons — a rhetorical device heightening the indictment. The high places on Israel\'s ridges were the actual sites of illicit worship; addressing the terrain itself implicates the geography of apostasy. Cf. 36:1 where the same mountains receive a word of consolation — structural reversal in the book.</p>',
    "3": '<p><strong>bamoteichem</strong> (\'your high places\'): <em>bamah</em> (pl. <em>bamot</em>) designates open-air elevated shrines, condemned from Leviticus 17 through Kings. Here YHWH announces that the sword will destroy the very sites where the people worshipped false gods — judgment through the mechanism of defeat and military desecration of the sanctuaries. <strong>Nevatim</strong> (\'demolished\'): razed, used of altars.</p>',
    "4": '<p><strong>chammanim</strong> (\'incense altars\'): etymology debated — possibly from <em>chammah</em> (sun), designating sun-pillars or incense stands associated with solar worship. The term appears in Leviticus 26:30 as a target of divine wrath. <strong>gillulim</strong> (\'idols\'): from <em>gll</em> (to roll), cognate with <em>gelal</em> (dung pellets) — a deliberately contemptuous coinage used 39x in Ezekiel alone. YHWH refuses to use a neutral word for the objects of Israel\'s devotion.</p>',
    "5": '<p><strong>gufei bnei Yisrael</strong> (\'corpses of the Israelites\'): the ultimate irony — the bodies of worshippers laid before the idols they served. The verb <strong>natati</strong> (\'I will put/give\') makes YHWH the agent, not a passive observer. The dead scattered before their idols enacts a kind of dark liturgy: the worshippers finally brought fully into the presence of their gods.</p>',
    "6": '<p><strong>yeshamu</strong> (\'they shall be desolated/made waste\'): Niphal of <em>shamam</em>, appearing 5x in this chapter. <em>Shamam</em> describes the condition of a land utterly stripped of population, agriculture, and life — the covenant curse of Leviticus 26:31-32 enacted. The high places that were crowded with worshippers will be as empty as the idols themselves.</p>',
    "7": '<p><strong>yeda\'tem ki-ani YHWH</strong> (\'you will know that I am YHWH\'): the refrain formula that punctuates all of Ezekiel — occurring ~72 times in the book. The goal of judgment is not annihilation but recognition: YHWH\'s actions are revelatory. The same formula is used for both judgment oracles (nations will know YHWH) and restoration oracles (Israel will know YHWH). Knowledge of YHWH is the telos of all divine action in Ezekiel.</p>',
    "8": '<p><strong>palitim</strong> (\'escapees/survivors\'): from <em>palat</em> (to escape, deliver). The remnant that escapes the sword is not preserved through their own merit but scattered among the nations — a partial rescue that simultaneously continues the humiliation. YHWH preserves a witness to his judgment even in the dispersion.</p>',
    "9": '<p><strong>lev zona</strong> (\'whoring heart\'): the marriage metaphor of apostasy that runs through Ezekiel 16, 20, and 23 is introduced here with its central term. <em>Zana</em> (to whore/commit harlotry) in prophetic usage describes covenantal infidelity — the exclusive relationship with YHWH violated by attraction to foreign gods. <strong>eineihem ha-zonot</strong> (\'their eyes that whored after\'): the eyes as the organ of desire that initiated the apostasy.</p>',
    "10": '<p><strong>veyadeu ki-lo chinnam</strong> (\'they shall know that not for nothing\'): the survivors will finally understand that the destruction was not random or unjust — it was the enacted covenant curse for specific covenant violations. The recognition formula here adds the crucial element of justified judgment: YHWH acted with moral coherence, not capriciousness.</p>',
    "11": '<p><strong>haka yad verego regel</strong> (\'strike with the hand and stamp with the foot\'): prophetic gestures of grief and horror — possibly also mimicking the executioner\'s final blow. The prophet embodies the divine anguish over the apostasy even as he announces judgment. Ezekiel\'s sign-acts throughout the book make his body the medium of prophetic communication.</p>',
    "12": '<p>The three modes of death announced — pestilence, sword, famine — are the classic biblical covenant-curse triad (Lev 26:25-26; Deut 28:21-22). The formula <strong>ve\'yadeu ki-ani YHWH</strong> closes the triad, ensuring even the judgment itself serves the purpose of divine self-revelation.</p>',
    "13": '<p><strong>raach nicho\'ach</strong> (\'pleasing/soothing aroma\'): the technical term from Leviticus for the aroma of acceptable sacrifice that ascends to YHWH. Here the phrase is used bitterly — the pleasing aroma rising from the high places, under the trees, on the mountains, was worship given to other gods. Every element of true sacrifice (the aroma, the elevation, the open-air altar) is present but directed to the wrong recipient.</p>',
    "14": '<p><strong>nosh\'mamah umeshimmah</strong> (\'desolate and waste\'): the doubled desolation intensifies the completeness of the coming devastation. The phrase <em>midbar diblata</em> (\'wilderness from Diblah/Riblah\') marks the geographical extent of the destruction from south to north — the wilderness of Riblah marking the northern border of the land. The <em>yeda\'tem</em> formula closes the chapter, making recognition of YHWH the final word.</p>'
},
"7": {
    "1": '<p>The oracle-reception formula again — but the message of chapter 7 is qualitatively different from everything before. This chapter is a sustained lament over finality, with a distinctive elevated/poetic style that breaks from Ezekiel\'s usual prose. The shift in register signals the gravity of what follows.</p>',
    "2": '<p><strong>qets</strong> (\'the end\'): the word Amos used for the northern kingdom\'s fate (Amos 8:2) is now applied to the southern. <em>Qets</em> denotes a terminal point — not merely a bad period but the cessation of something. <strong>arba kanfot ha\'aretz</strong> (\'four corners of the land\'): totalistic formula — every direction, nothing excluded. The end comes from all quadrants simultaneously.</p>',
    "3": '<p><strong>shafachti appi</strong> (\'I will pour out my wrath upon you\'): <em>aph</em> is both \'nose\' and \'wrath\' in Hebrew — the image of flaring nostrils as the original somatic register of anger. The pouring metaphor suggests wrath as accumulated liquid finally released, uncontainable and unstoppable. <strong>mishpatim</strong> (\'judgments\'): the deeds that fill the "end" are the divine verdicts — YHWH\'s legal actions against covenant breach.</p>',
    "4": '<p><strong>lo-tachon einecha</strong> (\'my eye will not spare you\'): the verb <em>chus</em> (to have compassion, spare) is used negatively here — the divine compassion that normally withholds judgment is explicitly withdrawn. Ezekiel 8:18 and 9:5 repeat this formula. The removal of divine mercy is itself a judicial act, not arbitrary cruelty but the withdrawal of a staying grace that was repeatedly refused.</p>',
    "5": '<p><strong>ra\'ah achat ra\'ah</strong> (\'a disaster, a singular disaster\'): the repetition of the word creates an ominous emphasis — \'a disaster, one disaster.\' The LXX reads <em>kakía mía kakía</em>. This singular unique disaster will be unlike the repeated warnings and partial judgments that preceded it. This is the final act.</p>',
    "6": '<p><strong>heqitz elayich</strong> (\'the end has awakened against you\'): <em>qetz</em> (end) is personified as a sleeping predator now roused. The verb <em>huqitz</em> (Hiphil of <em>quts</em>) means \'to awaken\' — judgment was dormant, patient; now it stirs. The wordplay <em>qetz</em>/<em>qits</em> (end/summer) echoes Amos 8:2\'s famous vision.</p>',
    "7": '<p><strong>hatsefira ba\'ah</strong> (\'the dawn has come, the doom has come\'): <em>tsefira</em> is rare — possibly \'morning\' or \'crown/garland\' (hapax in this sense) — pointing to an ironic dawning not of light but of doom. The day dawns but brings darkness. <strong>lo-har hechim</strong> (\'not a joyful shout on the mountains\'): the mountains that should echo with the joyful shout of harvest (Isa 16:10) will be silenced.</p>',
    "8": '<p><strong>qerov lishpoch chamati</strong> (\'soon I will pour out my fury upon you\'): <em>chamath</em> (fury, heat of anger) — a stronger term than <em>aph</em> — denotes the burning intensity of the divine anger that has been holding back. The second person singular address makes this intensely personal: YHWH speaks directly to the land/people as if face to face.</p>',
    "9": '<p><strong>lo-tachus einecha velo echmol</strong> (\'my eye will not spare and I will not pity\'): the doubled refusal of mercy — both the visual mode of compassion (<em>chus b\'ayin</em>, spare with the eye) and the emotional compassion (<em>chamal</em>, pity/have mercy) are withdrawn. The <em>yeda\'tem</em> formula again: judgment serves revelation.</p>',
    "10": '<p><strong>mateh parach hazadon tsats</strong> (\'the rod has blossomed, pride has budded\'): unusual agricultural metaphor. The \'rod\' is likely the rod of punishment/affliction that has now \'blossomed\' — it has come to full growth and is ready to execute. <em>Zadon</em> (pride/arrogance): the bloom of Israel\'s arrogance has triggered the bloom of its judgment. Nature\'s growth cycle becomes the metaphor for moral consequence.</p>',
    "11": '<p><strong>hachamas qam lemateh resha</strong> (\'violence has grown into a rod of wickedness\'): the violence that filled the land has become the instrument of its own destruction — a rod that punishes. This theme of sin becoming the agent of its own punishment is central to prophetic theology. <em>Lo-meylahem</em> (\'nothing of their wealth\') — no remainder survives.</p>',
    "12": '<p><strong>ba ha\'et higi\'a hayom</strong> (\'the time has come, the day has arrived\'): the prophetic \'day of YHWH\' language — a day that has been anticipated is now arriving. <strong>ha-mocher al-yismach</strong> (\'let not the buyer rejoice\'): commercial transactions will be meaningless — the land itself is forfeited, and buying property is pointless when everything is about to be seized by the invader.</p>',
    "13": '<p><strong>ki-hazon el-kol-hamonah lo yashuv</strong> (\'for the vision concerning its whole multitude will not turn back\'): the divine vision-word is irrevocable — once spoken and set in motion, it cannot be recalled or softened. The prophetic word in Ezekiel functions as divine performative speech: it brings into existence what it declares.</p>',
    "14": '<p><strong>taq\'u vataqoa</strong> (\'they blow the trumpet\'): the war trumpet signals mobilization, but no one goes to battle — the will to fight has been divinely removed. The trumpet sounds into an emptiness that reveals the completeness of judgment: no military response is possible because YHWH\'s wrath has paralyzed the defenders.</p>',
    "15": '<p>The three-fold judgment of sword, pestilence, and famine again (cf. 6:12), but here applied to specific locations: sword in the field, pestilence and famine within the city. The geography of doom is complete — there is no safe quarter. The siege creates an inner circle of starvation while the sword awaits those who try to escape.</p>',
    "16": '<p><strong>umiltetu vehayu</strong> (\'and those who escape, they will be\'): even the escapees are covered in divine judgment — they will be on the mountains \'like doves of the valleys\' (col-yon ha\'amaqim), each mourning alone. The comparison to solitary mourning doves captures the total breakdown of community: isolated, grieving, without purpose.</p>',
    "17": '<p><strong>kol-yadayim tirpenah</strong> (\'all hands shall go limp\'): the paralysis of terror — the inability to act, fight, or flee. The idiom <em>raphah yadayim</em> (limp/feeble hands) recurs in Isaiah, Jeremiah, and Zephaniah as the somatic register of total demoralization. <strong>berka\'ayim telaknah mayim</strong> (\'knees run with water\'): the physical sign of extreme fear, incontinence as the body\'s ultimate surrender.</p>',
    "18": '<p><strong>chagor saq</strong> (\'gird themselves with sackcloth\'): the mourning rite of sackcloth — worn against the skin as a sign of grief and abasement. <strong>ufachad yechasse</strong> (\'terror will cover them\'): <em>pachad</em> (dread, terror) — the paralyzing fear that removes the capacity for resistance. <strong>vel-kol-panim bushah</strong> (\'on all faces shame\'): universal shame as the condition of the defeated.</p>',
    "19": '<p><strong>kashpam batchutzot yashlichu</strong> (\'their silver they will throw into the streets\'): the ultimate economic collapse — wealth becomes worthless. <strong>kesef niddah yihyeh</strong> (\'their silver will be like a rejected thing\'): <em>niddah</em> (menstrual impurity) — silver described as ritually unclean and untouchable, the ultimate devaluation. <strong>beyom evrat YHWH</strong> (\'on the day of YHWH\'s wrath\'): the first explicit use of the \'day of YHWH\' formula in Ezekiel.</p>',
    "20": '<p><strong>tzvi adyo lega\'on samu</strong> (\'the beauty of his ornaments — they set it for pride\'): Israel\'s beautiful temple treasures (the <em>tzvi</em>, glory/beauty) were used to make idols. The divine gift of beauty — architecture, sacred objects, wealth — was perverted into the material of false worship. The very blessings became the instruments of the betrayal.</p>',
    "21": '<p><strong>unatativ byad hazarim levalah</strong> (\'I will give it as plunder to strangers to desecrate\'): YHWH actively hands Israel\'s treasured things to pagan desecrators — not as abandonment but as a deliberate act of judgment through the agency of enemies. The \'most wicked of the nations\' as YHWH\'s instruments echoes the Habakkuk theodicy: how can YHWH use the unrighteous to judge his people?</p>',
    "22": '<p><strong>utsefuni lo-ye\'asem</strong> (\'my treasured place shall be profaned\'): <em>tsafun</em> (that which is hidden/treasured/secret) — the innermost holy space, the sanctuary. YHWH turns his face away, allowing the profaners to enter and desecrate what he has until now protected. The divine withdrawal of protection makes the violence possible.</p>',
    "23": '<p><strong>asoh harattok</strong> (\'make the chain\'): a command to Ezekiel to forge a chain — a sign act of coming captivity. The land is full of bloodshed (<em>mishpat damim</em>) and the city full of violence (<em>chamas</em>). The chain anticipates the exile: Israel will be led away bound.</p>',
    "24": '<p><strong>miqdasheihem yechullalu</strong> (\'their sanctuaries shall be desecrated\'): plural <em>miqdashim</em> — all the holy places, not just Jerusalem. The word <em>challal</em> (desecrate/profane) is from the root meaning \'pierced/opened\' — to violate what was sealed and protected. The divine protection of the holy place is withdrawn, and the sacred is exposed to the profane.</p>',
    "25": '<p><strong>tavo charchurah</strong> (\'anguish comes\'): <em>charcharah</em> (trembling/anguish) — a rare term that combines physical and emotional distress. They will seek peace (<em>shalom</em>) but there will be none — the divine gift of <em>shalom</em> has been permanently interrupted. The false prophets\' cry of \'peace, peace\' (13:10) is answered by this declared absence of peace.</p>',
    "26": '<p><strong>chazon me\'at yavoh</strong> (\'calamity upon calamity shall come, and vision will follow vision\'): in a savage irony, the moment judgment falls is when visions multiply — but they are visions of doom, not salvation. <strong>Torah mekohen tovad</strong> (\'instruction from the priest is lost\'): the three channels of divine communication — vision (<em>chazon</em> from the prophet), instruction (<em>Torah</em> from the priest), counsel (<em>etsah</em> from the elder) — all simultaneously fail. The complete collapse of covenant mediation.</p>',
    "27": '<p><strong>hamelech yitabel</strong> (\'the king will mourn\'): the king himself becomes a mourner — dressed in garments of mourning rather than royal robes. The total inversion of the social order: the priest loses Torah, the elder loses counsel, the king loses power, the people lose security. <strong>yadayim am ha\'aretz tirpenah</strong> (\'the hands of the people of the land will go limp\'): the paralyzing terror now extends through all social strata. Divine judgment equalizes everyone in helplessness.</p>'
},
"8": {
    "1": '<p><strong>yad Adonai YHWH naflah alai</strong> (\'the hand of the Lord YHWH fell upon me\'): the phrase <em>yad YHWH</em> (hand of YHWH) marks ecstatic prophetic experience — a divine force seizing the prophet for vision or transport. Compare 1:3; 3:14, 22; 33:22; 40:1. The elders of Judah sitting before Ezekiel in exile suggests he has become a recognized spiritual authority among the exiles even before the formal destruction of Jerusalem.</p>',
    "2": '<p><strong>demut-mar\'eh esh</strong> (\'something with the appearance of fire\'): the figure that appears is identical in description to the throne-figure of chapter 1 — the deliberate verbal echo connects this vision to the divine chariot. From his loins downward: fire; from his loins upward: gleaming brightness like <em>hashmal</em> (electrum/amber). This is a theophanic appearance of the divine, not an angel.</p>',
    "3": '<p><strong>tziur haqin\'ah</strong> (\'the image of jealousy\'): <em>qin\'ah</em> (jealousy/zeal) is the covenantal emotion YHWH declares in the Decalogue: \'I, YHWH your God, am a jealous God\' (Ex 20:5). The idol placed at the gate of the altar provokes YHWH\'s jealousy by occupying the sacred space where only YHWH should be acknowledged. The idol is identified by the response it provokes in YHWH.</p>',
    "4": '<p><strong>kevod Elohei Yisrael</strong> (\'the glory of the God of Israel\'): the <em>kavod</em> that appeared in chapter 1 at the River Chebar is now seen in Jerusalem — still present, still resident, but about to observe the abominations that will cause it to depart. The kavod\'s presence here sets up the drama of chapters 8-11: the glory witnesses the unfaithfulness and then withdraws.</p>',
    "5": '<p><strong>miznafon la-sha\'ar ha-mizbeach</strong> (\'north of the altar gate\'): the north was considered the direction of divine approach (cf. Job 37:22; Isa 14:13). An idol placed at the north gate of the altar — the most theologically charged direction — is a maximum affront to YHWH. The cardinal points of the compass become the geography of apostasy in this chapter: north (v5), inner court (v6), entrance of the outer court (v7-12), north gate of the inner court (v14), east gate of the inner court (v16).</p>',
    "6": '<p><strong>lemarchaqeni me\'al miqdashi</strong> (\'to drive me far from my sanctuary\'): YHWH frames the abominations in terms of their effect on him — they push him away from his own house. The divine presence is sensitive, not automatic; persistent covenant violation creates a moral/relational incompatibility between YHWH and the space that was dedicated to his presence. Judgment is the consequence of the people successfully driving YHWH away.</p>',
    "7": '<p><strong>chayim chur bachomah</strong> (\'a hole in the wall\'): Ezekiel is commanded to dig through the wall — a prophetic act of investigation. The wall conceals something; what is hidden is worse than what is public. The inward/concealed nature of the abomination (the 70 elders in a secret chamber) represents the systemic nature of the apostasy: it is not just a public display but an internal practice of the leadership.</p>',
    "8": '<p>The command to dig (<em>chathor-lecha</em>) precedes the reveal — the prophet as investigator of hidden sin. The image of tunneling through a wall to see hidden chambers anticipates the revelation that follows. The progressively revealed layers of apostasy (idol at the gate, animals painted inside, women weeping, men facing east) represent a kind of tour of unfaithfulness moving from exterior to interior, from obvious to occult.</p>',
    "9": '<p><strong>re\'eh et-hato\'evot hara\'ot</strong> (\'see the great abominations\'): YHWH directs Ezekiel\'s vision — he sees what YHWH wants him to see. The tour of abominations is not Ezekiel\'s discovery but a divinely guided revelation of exactly how deep the apostasy runs. Each scene is observed at YHWH\'s prompting: \'come and see\' (<em>bo ur\'eh</em>) — v9, 13, 15, 17.</p>',
    "10": '<p><strong>kol tavnit remes uvehema sheketz</strong> (\'every form of creeping things and beasts and abominations\'): the inner chamber is covered with murals of unclean animals — the precise categories prohibited in Leviticus 11. The 70 elders worship before images of everything that Israel is forbidden to eat. The Levitical purity system is being systematically inverted in the secret worship chamber.</p>',
    "11": '<p><strong>shivim ish miziqnei beit Yisrael</strong> (\'seventy men of the elders of the house of Israel\'): the council of elders — 70 men as in Numbers 11:16-17 where 70 elders received the Spirit. The legitimate governance structure of Israel has been co-opted for secret idol worship. <strong>Ya\'azanyahu ben Shafan</strong>: named — the son of Shaphan the scribe (2 Kings 22:3), who read the discovered Torah scroll to Josiah. The family of reform is implicated in apostasy.</p>',
    "12": '<p><strong>bemachshak ish becheder maskito</strong> (\'each in his room of idols/carved images\'): <em>maskiyot</em> (carved images/rooms of imagery) — each elder has a private chamber of devotion. The corporate apostasy at the temple is matched by individual private idolatry. Their theological rationale: <strong>ein YHWH ro\'eh otanu</strong> (\'YHWH does not see us\') — YHWH has abandoned the land. The premise for the secret worship is the claim that divine oversight has ceased.</p>',
    "13": '<p>The divine \'come and see\' formula repeated — this is only the second of four scenes. Each scene is worse than the previous. YHWH is systematically showing Ezekiel the cumulative weight of Israel\'s unfaithfulness, building to the fullest possible indictment before announcing the judgment of chapters 9-11.</p>',
    "14": '<p><strong>nashim yoshvot mevakot et-haTammuz</strong> (\'women sitting weeping for the Tammuz\'): <em>Tammuz</em> is the Mesopotamian god of vegetation/fertility (Sumerian Dumuzi), whose annual death and descent to the underworld was mourned by women in ritual lamentation at midsummer. The cult was explicitly Babylonian — Ezekiel\'s exilic audience would recognize it immediately. The north gate of the inner court is devoted to foreign fertility-cult mourning.</p>',
    "15": '<p>The third \'come and see\' — greater abominations to come. The tour moves from animal-worship murals (8:10), to Tammuz-lamentation (8:14), to solar cult (8:16) — roughly tracing the geography of the temple courts from outer to inner, and also the chronological history of Israel\'s apostasy from Canaanite (<em>bamot</em>) to Mesopotamian to Egyptian/solar influences.</p>',
    "16": '<p><strong>esrim vachamisha ish</strong> (\'twenty-five men\'): the number may correspond to the 24 priestly divisions plus the high priest — the entire cultic leadership. <strong>mishtachavitim qedmah lashemesh</strong> (\'bowing down to the sun\'): <em>qedem</em> (east) — they face east, away from the Holy of Holies, toward the rising sun. This is the ultimate liturgical inversion: the worshippers of YHWH turn their backs on his dwelling to face a heavenly body.</p>',
    "17": '<p><strong>shalchu et-hazmorat el-appam</strong> (\'they put the branch to their nose\'): a notoriously obscure gesture — possibly a ritual act in solar or fertility worship (holding a plant toward the face in salutation or offering). Some emend to \'nose\' = face, others read it as a deliberate obscenity. Whatever the gesture, YHWH frames it as a provocation: they are outraging him and then returning to do <em>more</em> provocation. <em>Chamasam</em> (\'their violence\') — the sins accumulate.</p>',
    "18": '<p><strong>lo-tachus einai velo echmol</strong> (\'my eye will not spare and I will not pity\'): the identical refusal of mercy from 7:4, 9 — but now pronounced in the context of the observed abominations. The justice of the upcoming slaughter in chapter 9 is grounded in the evidence of chapters 8: YHWH has seen everything in the secret chambers and at the east gate. <strong>veqare\'u be\'oznai qol gadol</strong> (\'they cry in my ears with a loud voice\'): even loud prayer in the coming crisis will not be heard.</p>'
},
"9": {
    "1": '<p><strong>paqudat ha\'ir</strong> (\'those charged with the punishment of the city\'): <em>paqudat</em> (oversight/charge/punishment) — the root <em>paqad</em> is both \'to visit\' (in care) and \'to visit\' (in judgment). Six executioners approach from the north — the direction from which Babylon will come. The summoning of divine executioners frames the coming slaughter not as human atrocity but as divinely authorized judgment.</p>',
    "2": '<p><strong>keli mashchet beyado</strong> (\'a weapon of destruction in his hand\'): each executioner carries <em>keli mashchet</em> — an instrument of shattering/destruction. The one exception is the man <strong>levush habadim</strong> (\'dressed in linen\'): priestly linen (<em>bad</em>) marks him as a different order of being — a priestly-scribal figure who marks the saved, not executes the judged. <strong>qeset hasopher</strong> (\'writing case of the scribe\'): an ink-holder for marking.</p>',
    "3": '<p><strong>ukhvod Elohei Yisrael na\'alah</strong> (\'the glory of the God of Israel went up\'): the glory begins its departure. From the <em>kerub</em> (cherub) on which it rested — its traditional seat above the ark in the Holy of Holies — it moves to the threshold of the temple. This is the first stage of the glory\'s withdrawal that will culminate in 10:18-19 and 11:23. The departure of the glory is the most theologically catastrophic event in the entire book.</p>',
    "4": '<p><strong>vesimta tav al-mitzchotam</strong> (\'put a mark on the foreheads\'): <em>tav</em> (תָּו) is the last letter of the Hebrew alphabet, and in paleo-Hebrew script was written as an X or + shape. The mark identifies those who <strong>ne\'enachim v\'ne\'anaqim</strong> (\'sigh and groan\') over all the abominations done in Jerusalem. The criterion for salvation is not ritual performance but grief-identification with YHWH\'s perspective on the apostasy. Those who mourn over sin are marked as those who share divine values.</p>',
    "5": '<p><strong>acharav amar b\'oznai</strong> (\'to the others he said in my hearing\'): Ezekiel hears the divine command to the executioners, not merely as a vision but as audible speech in his ears. The command to follow the scribe through the city mirrors the Exodus: the blood on the doorposts marked the saved; here the ink-mark on the forehead marks those who are passed over. The executioners begin with the elders before the sanctuary — judgment begins at the house of God (cf. 1 Pet 4:17).</p>',
    "6": '<p><strong>el-zaqen bachur u\'vetulah vetaf u\'nashim harogu lemashchit</strong> (\'old man, young man, maiden, infant, and women — kill to destruction\'): the totalistic list — no age or sex is exempt from the judgment. The sole exception: <strong>veal-kol-ish asher-alav hatav al-tiqrabu</strong> (\'do not come near any man on whom is the mark\'). <em>Ubeit hamiqdash tachelu</em> (\'from my sanctuary you shall begin\'): judgment starting in the temple — the most horrifying reversal, since the temple was supposed to be the place of refuge.</p>',
    "7": '<p><strong>tumeu et-habayit</strong> (\'defile the house\'): the executioners are commanded to defile the temple — the very space that was supposed to be the holiest place in Israel is made a slaughterhouse. The <em>chatzerot mil\'u chalal</em> (\'fill the courts with the slain\') creates a spatial horror: the courts for sacrificial worship become the courts of corpses. YHWH himself commands the defilement of his own house as the final statement of judgment on Israel\'s apostasy.</p>',
    "8": '<p><strong>veten Ezekiel el-panav</strong> (\'and I fell on my face\'): Ezekiel\'s intercession — the same posture of pleading as Moses (Num 14:5; 16:22). <strong>ha\'atah meshalecheta et kol she\'erit Yisrael</strong> (\'are you going to destroy all the remnant of Israel?\'): the prophet\'s one intercessory cry in the midst of the vision. Unlike Jeremiah (7:16; 11:14), Ezekiel is not explicitly told not to intercede, but the answer he receives makes clear that the judgment cannot be arrested.</p>',
    "9": '<p><strong>avon beit Yisrael uYehudah gadol meod meod</strong> (\'the iniquity of the house of Israel and Judah is very, very great\'): the double intensifier <em>meod meod</em> (very, very) drives home the disproportionality — this is not slight unfaithfulness but massive, accumulated, comprehensive covenant violation. YHWH names two specific theological failures: (1) the land is full of blood (<em>dam</em>); (2) the city is full of perversion (<em>mateh</em>). Both are covenant violations with capital consequences in Torah.</p>',
    "10": '<p><strong>gam ani lo-tachus einai velo echmol</strong> (\'I also — my eye will not spare and I will not pity\'): the formula from 7:4,9 and 8:18 now from YHWH\'s own lips in direct speech to the interceding Ezekiel. The \'I also\' (<em>gam ani</em>) is devastating in its context: Ezekiel has just shown compassion (\'will you destroy the remnant?\'); YHWH responds with the divine reciprocity of <em>derakham beroshham natati</em> — \'their way I repay on their heads.\'</p>',
    "11": '<p><strong>ani asiti ka\'asher tzivitani</strong> (\'I have done as you commanded me\'): the linen-clad scribe reports completion. The chapter ends on the note of the one mission accomplished: the mark has been placed. Against the total devastation of the city, the marking of the remnant is the sole exception. The divine plan that preserves a remnant while executing judgment on the apostate majority is achieved with precise obedience.</p>'
},
"10": {
    "1": '<p><strong>raqia asher al-rosh hakeruvim</strong> (\'the firmament that was over the heads of the cherubim\'): the same <em>raqia</em> (expanse/firmament) that appeared in 1:22 above the four living creatures. The identification of the creatures here as <em>keruvim</em> (cherubim) — which will be made explicit in v. 20 — bridges the throne vision of chapter 1 to the temple context of chapters 8-11. <strong>even sapir kemar\'eh</strong> (\'like sapphire stone in appearance\'): the sapphire-blue throne platform connecting to the throne-chariot.</p>',
    "2": '<p><strong>galgelei esh</strong> (\'burning coals of fire\'): the man in linen is commanded to take fire from between the cherubim and scatter it over the city — the same coals that will be scattered over Jerusalem as judgment. The fire comes from within the divine chariot, making the judgment itself an emanation of divine holiness. What was the fire of divine presence becomes the fire of divine judgment when directed toward an apostate city.</p>',
    "3": '<p><strong>ha\'anan male et-hechatzer hap\'nimit</strong> (\'the cloud filled the inner court\'): the glory-cloud (<em>anan</em>) fills the inner court just as it filled the tabernacle at its dedication (Ex 40:34-35) and the temple at Solomon\'s dedication (1 Kgs 8:10-11). But here the filling of the cloud precedes the <em>departure</em> of the glory — it is a last manifestation of divine presence before withdrawal, not an inaugural occupation.</p>',
    "4": '<p><strong>varam kevod YHWH me\'al hakerub al-miftan habayit</strong> (\'the glory of YHWH rose from upon the cherub to the threshold of the house\'): the second stage of the glory\'s departure — from the cherub (the ark/mercy seat) to the threshold (the doorway of the temple). The glory is moving toward the exit. <strong>vatimale habayit et-he\'anan</strong> (\'the house was filled with the cloud\'): paradoxically, as the glory prepares to leave, its visible manifestation intensifies. Departure is preceded by a final overwhelming display.</p>',
    "5": '<p><strong>qol kanfei hakeruvim nishma ad-hechatzer hachitzonah</strong> (\'the sound of the wings of the cherubim was heard to the outer court\'): the sound is compared to <strong>kol El Shaddai bedabro</strong> (\'the voice of God Almighty when he speaks\'). <em>El Shaddai</em> — the patriarchal divine name (Gen 17:1; 28:3; Ex 6:3) emphasizing divine power and sufficiency — appears here as the register for the thunder-sound of the cherubim\'s wings. The chariot is audible as divine speech.</p>',
    "6": '<p>The man in linen obeys the command to take coals. His movement — from the outer area to standing between the wheels — marks him as able to navigate between the human-accessible outer courts and the divine-presence space between the cherubim. He is a mediating figure: priestly linen, scribal tools, access to the divine inner sanctum, commissioned for judgment on the city.</p>',
    "7": '<p><strong>yishlach ish halomed et-yado el-toch ha\'esh</strong> (\'the cherub stretched out his hand into the fire\'): the fire that the linen-clad man is to take is given to him by a cherub directly — the divine agent of judgment hands the judicial fire to the priestly agent of judgment. The chain of delegation (YHWH → cherub → linen-man → city) distributes the agency of judgment while maintaining its ultimate divine source.</p>',
    "8": '<p><strong>vayera el-hakeruvim tabnit yad adam tachtat kanfeihem</strong> (\'there appeared on the cherubim the form of a human hand beneath their wings\'): a detail repeated from 1:8 — the human hands beneath the wings of the living creatures. In chapter 1 this was part of the initial vision; here the identification reinforces that these are the same figures. The human element in the divine chariot emphasizes the relational/personal nature of the divine presence.</p>',
    "9": '<p><strong>ofan echad etzel hakerub echad</strong> (\'one wheel beside each cherub\'): the four-wheel structure of the chariot repeated from 1:15-21. <strong>kemar\'eh even tarshish</strong> (\'like the appearance of tarshish stone\'): <em>tarshish</em> stone is variously identified as beryl, chrysolite, or topaz — a lustrous greenish-blue gem. The same description in 1:16; Daniel 10:6; and Rev 21:20 places <em>tarshish</em> consistently in the register of divine-appearance glory.</p>',
    "10": '<p>The four wheels are identical to each other (<em>mareh echad laarba\'atam</em>) — no hierarchy, no differentiation among the wheels. This uniformity emphasizes the perfect integration and unified movement of the chariot. The divine throne-chariot has no structural hierarchy among its wheels, just as the four living creatures were coordinate rather than subordinate to each other.</p>',
    "11": '<p><strong>el-ha-rosh yelu acharav yelu</strong> (\'toward the head they go; after the head they go\'): direction of movement determined by the head — wherever the <em>rosh</em> turns, the entire chariot turns without rotating. This describes perfect responsiveness to a single will: the chariot is omnidirectional precisely because it is perfectly subordinate to the divine will directing it.</p>',
    "12": '<p><strong>kol-besaram vegabotam veyedeihem vekanfeihem vehaofanim mele\'im einayim saviv</strong> (\'their entire bodies, their backs, their hands, their wings, and the wheels — all full of eyes around\'): the omni-perceptive nature of the divine chariot — eyes on every surface. The divine presence is omniscient as well as omnipresent. Nothing in the created order is outside YHWH\'s perception; the chariot\'s many eyes embody the truth that \'his eyes are on all his ways\' (Jer 16:17; Prov 15:3).</p>',
    "13": '<p><strong>lagalgal qora lahem</strong> (\'to the wheel it was called \'the whirling thing\'\'): <em>hagalgal</em> — possibly an intensified form of <em>ofan</em> (wheel) emphasizing rapid rotation. Ezekiel notes what the creatures themselves call their wheels — an insider detail that gives the vision the quality of overheard divine speech, not merely observed phenomenon.</p>',
    "14": '<p><strong>arba panim le\'echad</strong> (\'four faces belonging to one\'): the four faces of each creature listed — but here, significantly, the first face is <em>hakerub</em> (the cherub face) rather than the <em>shor</em> (ox) of 1:10. The substitution has generated extensive scholarly discussion: possibly \'cherub face\' = the ox face seen from the cherubic perspective, or possibly a deliberate difference marking the Jerusalem temple context. Either way, the identification of the creatures as cherubim is being established.</p>',
    "15": '<p><strong>vatinase hakeruvim</strong> (\'the cherubim rose up\'): the first movement of the chariot-cherubim since the vision of departure began. They are identified: <em>hi hachayyah asher ra\'iti binehar-kevar</em> (\'it is the living creature that I saw by the River Chebar\'). Ezekiel explicitly connects the two visions — the creatures of chapter 1 are the same as those in the temple vision. The continuity of the divine chariot in both locations affirms that the same divine presence was at the river and in the temple.</p>',
    "16": '<p><strong>beseet hakeruvim et-kanfeihem larus me\'al ha\'aretz lo-yisabbu haofanim miletselam</strong> (\'when the cherubim went, the wheels went beside them; when the cherubim lifted their wings to rise from the earth, the wheels did not turn from beside them\'): perfect synchronization — the wheels do not act independently of the cherubim. The whole chariot moves as a unity, every part responsive to the same animating spirit.</p>',
    "17": '<p><strong>ki ruach hachayah bahem</strong> (\'for the spirit of the living creature was in them\'): the <em>ruach</em> (spirit/breath/wind) of the living creatures animates the wheels — they share a single animating principle. In 1:20-21, this same <em>ruach</em> was the key to the chariot\'s movement. The divine chariot is not a mechanism but a living, spiritually unified entity — which is why it moves in perfect responsiveness to the divine will.</p>',
    "18": '<p><strong>vayetse kevod YHWH me\'al miftan habayit</strong> (\'the glory of YHWH departed from over the threshold of the house\'): the critical moment — the glory leaves the temple building. From v4 (glory at the threshold) to v18 (glory departing from the threshold), the stage is set: the divine presence has now moved outside the building entirely. This is not merely the ark being captured (1 Sam 4) — it is the voluntary withdrawal of YHWH\'s presence from his own house in response to its defilement.</p>',
    "19": '<p><strong>vaya\'amdu petach sha\'ar beit YHWH hamizrachit</strong> (\'they stood at the entrance of the east gate of the house of YHWH\'): the glory moves to the east gate — the gate through which the sun rises and toward which the apostate priests had been bowing (8:16). The deliberate choice of the east gate for the glory\'s penultimate resting place may be a reversal: the gate that was used for solar worship now receives the true divine glory as it exits. Compare 43:1-4 where the glory returns through this same east gate.</p>',
    "20": '<p><strong>hi hachayyah asher ra\'iti tachat Elohei Yisrael binehar-kevar</strong> (\'it is the living creature that I saw under the God of Israel by the River Chebar\'): the explicit identification, stated plainly and definitively. The creatures beneath the divine throne at the Chebar River and the cherubim in the Jerusalem temple are the same. This retrospective identification validates both visions simultaneously and affirms that Israel\'s God is not geographically limited — he was on a moveable throne at the Chebar River, and that same throne now departs from Jerusalem.</p>',
    "21": '<p><strong>arba panim le\'echad ve\'arba knafayim le\'echad</strong> (\'four faces for each one and four wings for each one\'): Ezekiel catalogs the identifying features of the cherubim to clinch the identification with the chapter 1 creatures. The enumeration is precise: four faces, four wings (vs. Isaiah\'s six-winged seraphim in Isa 6), with human hands beneath the wings. The consistent anatomy across the two visions is the proof of identity.</p>',
    "22": '<p><strong>udemut peneihem hemah hapanim asher ra\'iti al-nehar-kevar</strong> (\'the likeness of their faces — they were the faces that I saw at the River Chebar\'): the chapter ends with the full identification confirmed. The vision has now come full circle from chapter 1: the living creatures of the throne-chariot are the cherubim of the temple; the same divine kavod was present in Babylon and in Jerusalem; and now it is departing from Jerusalem. The next move of the glory (11:23 — to the Mount of Olives) completes the departure sequence.</p>'
}
}

